const fs = require('fs');

function deriveWhy(runs, alerts, watches, lastStatus, trend) {
  const r = parseInt(runs) || 0;
  const a = parseInt(alerts) || 0;
  const w = parseInt(watches) || 0;

  if (trend === '—' || trend === '') {
    return r <= 1 ? 'Single run — no trend data yet' : 'No signal pattern established';
  }
  if (trend.includes('escalating')) {
    if (a >= r) return `Alerts in every run (${a}/${r})`;
    return `Alert rate ${a}/${r} runs; last status ${lastStatus}`;
  }
  if (trend.includes('settling')) {
    if (w > 0) return `Alerts declining; ${w} watch(es) pending — monitoring`;
    return `Alert count falling; last status ${lastStatus}`;
  }
  if (trend.includes('stable')) {
    if (a === 0 && w === 0) return `Consistently clear across ${r} runs`;
    if (a > 0) return `Recurring alerts (${a}/${r}) but no change in pattern`;
    if (w > 0) return `Active watch(es) (${w}) — no new alerts`;
    return `Steady pattern across ${r} runs`;
  }
  return '';
}

const lines = FILE_CONTENT.split('\n');
const output = [];
let inTable = false;
let headerLine = false;

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];

  // Detect table header for our domain tables
  if (line.match(/^\| Report Type\s*\| Runs\s*\| Alerts\s*\| Watches\s*\| Last Status\s*\| Trend\s*\|/)) {
    // Already has Why column?
    if (line.includes('Why')) {
      output.push(line);
      headerLine = false;
      inTable = true;
    } else {
      output.push(line.replace(/\|\s*$/, '| Why |'));
      headerLine = true;
      inTable = true;
    }
    continue;
  }

  // Separator row
  if (inTable && line.match(/^\|[\s\-|]+\|/) && line.includes('---')) {
    if (headerLine) {
      // Count existing separators and add one more
      const cols = line.split('|').filter(c => c.trim().length > 0);
      if (cols.length === 6) {
        output.push(line.replace(/\|\s*$/, '| --- |'));
      } else {
        output.push(line);
      }
      headerLine = false;
    } else {
      output.push(line);
    }
    continue;
  }

  // Data rows
  if (inTable && line.startsWith('|') && !line.includes('---')) {
    const parts = line.split('|').map(p => p.trim()).filter((_, i, arr) => i > 0 && i < arr.length - 1);
    if (parts.length === 6) {
      const [reportType, runs, alerts, watches, lastStatus, trend] = parts;
      const why = deriveWhy(runs, alerts, watches, lastStatus, trend);
      output.push(`| ${reportType} | ${runs} | ${alerts} | ${watches} | ${lastStatus} | ${trend} | ${why} |`);
    } else if (parts.length === 7) {
      // Already has Why column — leave alone
      output.push(line);
    } else {
      output.push(line);
    }
    continue;
  }

  if (!line.startsWith('|')) {
    inTable = false;
    headerLine = false;
  }

  output.push(line);
}

