function conviction(x) {
  if (x.fStar < 0) return '⊘ skip';
  if (x.fStar >= 0.25 && x.tier === 'prime') return 'HIGH';
  if (x.fStar >= 0.20 || x.tier === 'prime') return 'MEDIUM';
  return 'LOW';
}

