  const f = x.fStar;
  if (f < 0) {
    // NEUTRAL diffuse → strangle (vol play); otherwise skip
    if (x.ent > 0.70) return 'Long strangle (vol play — no directional edge)';
    return '⊘ no edge — skip';
  }
  if (x.conflict) return 'Long straddle (direction conflict — bet on move, not direction)';
  const dir = x.oD || (x.verdict === 'BULLISH' ? 'LONG' : x.verdict === 'NEUTRAL' ? null : null);
  if (dir === 'LONG') {
    if (f > 0.20) return 'Sell cash-secured puts → covered call if assigned';
    return 'Sell cash-secured puts (lower conviction — defined risk entry)';
  }
  if (dir === 'SHORT') return 'Buy puts';
  return '—';
}

